import { point as turfPoint } from '@turf/helpers';

import { getArrowsAngles } from './get-arrows-angles.js';
import type {
  Connection,
  GeoJSONFeature,
  InternalConnectionLayerProps,
} from '../../../types/connection-layer.js';

interface ParseGeoJsonDataProps<T extends Connection>
  extends Required<
    Pick<InternalConnectionLayerProps<T>, 'directionIndicator'>
  > {
  geoJsonData: GeoJSON.FeatureCollection;
}

const getConnectionGeoJSONFeature = (
  feature: GeoJSONFeature<GeoJSON.LineString>,
  angle: number,
  coordinates: number[],
): GeoJSONFeature<GeoJSON.Point> =>
  turfPoint(coordinates, { ...feature.properties, __angle: angle });

export const parseDirectionDataToGeoJSON = <T extends Connection>(
  props: ParseGeoJsonDataProps<T>,
): GeoJSON.FeatureCollection => {
  const { geoJsonData, directionIndicator } = props;

  const features: GeoJSONFeature<GeoJSON.Point>[] = [];

  for (let i = 0; i < geoJsonData.features.length; i++) {
    const feature = geoJsonData.features[
      i
    ] as GeoJSONFeature<GeoJSON.LineString>;

    const { coordinates } = feature.geometry;

    const { endMarkerAngle, startMarkerAngle } = getArrowsAngles(coordinates);

    const showStartArrow = directionIndicator !== 'end';
    const showEndArrow = directionIndicator !== 'start';

    const startCoordinate = coordinates[0];
    const endCoordinate = coordinates[coordinates.length - 1];

    if (showStartArrow) {
      const startPoint = getConnectionGeoJSONFeature(
        feature,
        startMarkerAngle,
        startCoordinate,
      );

      features.push({
        ...startPoint,
        properties: {
          ...startPoint.properties,
          id: `${feature.properties.id}-direction-start`,
        },
      });
    }

    if (showEndArrow) {
      const endPoint = getConnectionGeoJSONFeature(
        feature,
        endMarkerAngle,
        endCoordinate,
      );

      features.push({
        ...endPoint,
        properties: {
          ...endPoint.properties,
          id: `${feature.properties.id}-direction-end`,
        },
      });
    }
  }

  return {
    ...geoJsonData,
    features,
  };
};
